import { useEffect, useState } from "react";

function BookingPage() {

    const [fromDate, setFromDate] =
        useState("");

    const [toDate, setToDate] =
        useState("");

    const [license, setLicense] =
    useState(null);

    const [totalAmount, setTotalAmount] =
    useState(0);

    const pricePerDay = 2500;

    useEffect(() => {

    if (fromDate && toDate) {

        const startDate =
            new Date(fromDate);

        const endDate =
            new Date(toDate);

        const differenceInTime =
            endDate - startDate;

        const days =
            differenceInTime /
            (1000 * 60 * 60 * 24) + 1;

        const amount =
            days * pricePerDay;

        setTotalAmount(amount);
    }

}, [fromDate, toDate]);

    const handleBooking = () => {

        console.log(fromDate);

        console.log(toDate);

        console.log(license);

        alert("Booking Submitted");
    };

    return (

        <div
            style={{
                padding: "30px"
            }}
        >

            <h1>

                Car Booking Page

            </h1>

            <br />

            <div>

                <label>

                    From Date

                </label>

                <br />

                <input
                    type="date"

                    value={fromDate}

                    onChange={(e) =>
                        setFromDate(e.target.value)
                    }

                    style={{
                        padding: "10px",
                        width: "300px"
                    }}
                />

            </div>

            <br />

            <div>

                <label>

                    To Date

                </label>

                <br />

                <input
                    type="date"

                    value={toDate}

                    onChange={(e) =>
                        setToDate(e.target.value)
                    }

                    style={{
                        padding: "10px",
                        width: "300px"
                    }}
                />

            </div>

            <br />

            <div>

                <label>

                    Upload Driving License

                </label>

                <br />

                <input
                    type="file"

                    onChange={(e) =>
                        setLicense(e.target.files[0])
                    }
                />

            </div>

            <br />
        
            <button

                onClick={handleBooking}

                style={{
                    padding: "12px",
                    backgroundColor: "black",
                    color: "white",
                    border: "none",
                    borderRadius: "5px",
                    cursor: "pointer"
                }}
            >

                Confirm Booking

            </button>

        </div>
    );
}

export default BookingPage;
